module.exports = async (args) => {
  const fs   = require('fs');
  const path = require('path');

  const inputFile = args.inputFileObj._id;
  const dir       = path.dirname(inputFile);
  const inputExt  = path.extname(inputFile).toLowerCase();
  const inputBase = path.basename(inputFile, inputExt).toLocaleLowerCase('tr-TR');

  const deleteAlwaysExts    = new Set(['.ttf', '.otf', '.woff', '.woff2', '.eot']);
  const deleteSameNameExts  = new Set(['.txt', '.nfo', '.url', '.html', '.htm']);
  const imageExts           = new Set(['.jpg', '.jpeg', '.png', '.webp', '.bmp']);
  const safeImageBases      = new Set([
    'poster', 'fanart', 'backdrop', 'banner', 'clearart',
    'logo', 'thumb', 'folder', 'cover', 'landscape',
  ]);

  const deleted = [];
  try {
    for (const file of fs.readdirSync(dir)) {
      if (file === path.basename(inputFile)) continue;
      const ext  = path.extname(file).toLowerCase();
      const base = path.basename(file, ext).toLocaleLowerCase('tr-TR');
      const full = path.join(dir, file);
      try {
        if (fs.statSync(full).isDirectory()) continue;
        if (deleteAlwaysExts.has(ext)) {
          fs.unlinkSync(full); deleted.push(file);
        } else if (deleteSameNameExts.has(ext) && base === inputBase) {
          if (ext === '.nfo') {
            try {
              const content = fs.readFileSync(full, 'utf8');
              if (content.includes('type="tmdb"') || content.includes('<episodedetails>') ||
                  content.includes('<movie>') || content.includes('<tvshow>')) {
                args.jobLog('Skipping metadata NFO: ' + file);
                continue;
              }
            } catch (e) { /* unreadable — fall through to delete */ }
          }
          fs.unlinkSync(full); deleted.push(file);
        } else if (imageExts.has(ext) && !safeImageBases.has(base) && !/^season/.test(base) && base === inputBase) {
          fs.unlinkSync(full); deleted.push(file);
        }
      } catch (e) { args.jobLog('Could not delete ' + file + ': ' + e.message); }
    }
  } catch (e) { args.jobLog('Dir scan error: ' + e.message); }

  args.jobLog(deleted.length
    ? 'Deleted ' + deleted.length + ' sidecar(s): ' + deleted.join(', ')
    : 'No sidecar files to delete.');
  return { outputFileObj: args.inputFileObj, outputNumber: 1, variables: args.variables };
};

module.exports = async (args) => {
  const fs   = require('fs');
  const path = require('path');
  const { spawnSync, spawn } = require('child_process');

  const inputFile  = args.inputFileObj._id;
  const dir        = path.dirname(inputFile);
  const inputExt   = path.extname(inputFile).toLowerCase();
  const inputBase  = path.basename(inputFile, inputExt).toLocaleLowerCase('tr-TR');

  const streams      = (args.inputFileObj.ffProbeData || {}).streams || [];
  const audioStreams  = streams.filter(s => s.codec_type === 'audio');
  const subStreams    = streams.filter(s => s.codec_type === 'subtitle');

  const TR_LANGS   = new Set(['tur', 'tr']);
  const KEEP_SUB   = new Set(['tur', 'tr', 'eng', 'en', 'und']);
  const KEEP_AUDIO = new Set(['eng', 'en', 'tur', 'tr', 'jpn', 'ja', 'und', '']);
  const SUB_EXTS   = new Set(['.srt', '.ass', '.ssa', '.vtt', '.sub', '.sup']);
  const getLang    = s => (s.tags && s.tags.language ? s.tags.language.toLowerCase() : 'und');

  // Audio: keep KEEP_AUDIO langs + explicit original + first track as safety
  const CODEC_QUALITY = { truehd: 10, flac: 9, dts: 7, eac3: 7, ac3: 5, aac: 4, mp3: 3, opus: 2, vorbis: 2 };
  const codecScore    = s => CODEC_QUALITY[s.codec_name] || 1;
  const bitrateOf     = s => parseInt((s.tags && (s.tags['BPS-eng'] || s.tags['BPS'])) || s.bit_rate || '0', 10);
  const explicitOrig  = audioStreams.find(s => s.disposition && s.disposition.original === 1);
  const bestQuality   = audioStreams.slice().sort(
    (a, b) => (codecScore(b) - codecScore(a)) || (bitrateOf(b) - bitrateOf(a))
  )[0];
  const originalTrack = explicitOrig || bestQuality;

  const keepAudio  = audioStreams.filter(s =>
    KEEP_AUDIO.has(getLang(s)) || (originalTrack && s.index === originalTrack.index) || (audioStreams[0] && s.index === audioStreams[0].index)
  );
  const finalAudio = keepAudio.length > 0 ? keepAudio : (audioStreams.length > 0 ? [audioStreams[0]] : []);

  // Always reorder when a Turkish track exists — TR first regardless of filtering
  let audioMapsToKeep = null;
  const hasTRAudio = finalAudio.some(s => TR_LANGS.has(getLang(s)));
  const audioWasFiltered = finalAudio.length < audioStreams.length;

  if (audioWasFiltered || hasTRAudio) {
    if (hasTRAudio) {
      const trTracks    = finalAudio.filter(s =>  TR_LANGS.has(getLang(s)));
      const otherTracks = finalAudio.filter(s => !TR_LANGS.has(getLang(s)));
      audioMapsToKeep = [...trTracks, ...otherTracks].map(s => s.index);
    } else {
      audioMapsToKeep = finalAudio.map(s => s.index);
    }
    args.jobLog('Audio: keeping indices ' + audioMapsToKeep.join(', ') +
      (audioWasFiltered ? ' (dropped other dubs)' : '') +
      (hasTRAudio ? ' (TR first)' : ''));
  }

  // External subtitle detection — ONLY files whose name starts with this video's basename
  // to avoid grabbing sibling episode subtitles (e.g. S01E02.tr.srt while processing S01E01)
  let extSubFiles = [];
  if (!inputBase) {
    args.jobLog('inputBase empty — skipping external sub scan.');
  } else
  try {
    extSubFiles = fs.readdirSync(dir)
      .filter(f => {
        if (f === path.basename(inputFile)) return false;
        const ext     = path.extname(f).toLowerCase();
        const fLower  = f.toLocaleLowerCase('tr-TR');
        const full    = path.join(dir, f);
        return SUB_EXTS.has(ext) &&
               fLower.startsWith(inputBase) &&
               (fLower.length === inputBase.length || /^[.\s_\-\[\(]/.test(fLower[inputBase.length])) &&
               fs.statSync(full).isFile();
      })
      .map(f => path.join(dir, f));
  } catch (e) { args.jobLog('External sub scan error: ' + e.message); }

  // Convert SRT/SUB to UTF-8 — includes UTF-16 for subtitles from Turkish sites
  const convertedSubs = [];
  for (const sf of extSubFiles) {
    const ext = path.extname(sf).toLowerCase();
    if (ext === '.srt' || ext === '.sub') {
      const tmpPath = sf + '.utf8tmp';
      let used = sf;
      try {
        const chk = spawnSync('iconv', ['-f', 'UTF-8', '-t', 'UTF-8', sf], { encoding: 'buffer', timeout: 30000 });
        if (chk.status === 0) {
          args.jobLog(path.basename(sf) + ' already UTF-8');
        } else {
          for (const enc of ['UTF-16LE', 'UTF-16BE', 'WINDOWS-1254', 'ISO-8859-9', 'ISO-8859-1', 'WINDOWS-1252']) {
            const r = spawnSync('iconv', ['-f', enc, '-t', 'UTF-8', '-o', tmpPath, sf], { encoding: 'utf8', timeout: 30000 });
            if (r.status === 0) {
              args.jobLog('Converted ' + path.basename(sf) + ' from ' + enc + ' to UTF-8');
              used = tmpPath; break;
            }
          }
          if (used === sf) args.jobLog('Could not detect charset for ' + path.basename(sf) + ', using as-is');
        }
      } catch (e) { args.jobLog('iconv error for ' + path.basename(sf) + ': ' + e.message); }
      convertedSubs.push(used);
    } else { convertedSubs.push(sf); }
  }

  const embKeep        = subStreams.filter(s => KEEP_SUB.has(getLang(s)));
  const needsSubFilt   = embKeep.length < subStreams.length;
  const hasExtSubs     = convertedSubs.length > 0;
  const needsAudioFilt = audioMapsToKeep !== null;

  if (!needsSubFilt && !hasExtSubs && !needsAudioFilt) {
    args.jobLog('No stream changes needed.');
    for (const sf of convertedSubs) { if (sf.endsWith('.utf8tmp')) { try { fs.unlinkSync(sf); } catch(e) {} } }
    return { outputFileObj: args.inputFileObj, outputNumber: 2, variables: args.variables };
  }

  // workDir güvenlik kontrolü: film/dizi klasörüne yazılmasını engelle
  const outBasename  = path.basename(inputFile, inputExt) + '.mkv';
  const inputDir     = path.dirname(inputFile);
  const safeWorkDir  = (args.workDir && args.workDir !== inputDir && !inputDir.startsWith(args.workDir))
    ? args.workDir : '/tdarr-cache';
  const outputFile   = path.join(safeWorkDir, 'tdarr-work-' + Date.now(), outBasename);
  const workParent  = path.dirname(outputFile);
  try { fs.mkdirSync(workParent, { recursive: true }); } catch(e) {}

  const ff = ['-y', '-i', inputFile];
  for (const s of convertedSubs) ff.push('-i', s);

  const IMAGE_CODECS  = new Set(['mjpeg', 'png', 'bmp', 'gif', 'tiff', 'webp']);
  const primaryVideo  = streams.find(s => s.codec_type === 'video' && !IMAGE_CODECS.has(s.codec_name));
  if (primaryVideo) {
    ff.push('-map', '0:' + primaryVideo.index);
  } else {
    ff.push('-map', '0:v?');
  }

  if (needsAudioFilt) {
    for (const idx of audioMapsToKeep) ff.push('-map', '0:' + idx);
  } else { ff.push('-map', '0:a?'); }

  if (subStreams.length > 0) {
    if (needsSubFilt) { for (const sub of embKeep) ff.push('-map', '0:' + sub.index); }
    else { ff.push('-map', '0:s?'); }
  }
  convertedSubs.forEach((sf, i) => ff.push('-map', (i + 1) + ':0'));
  ff.push('-map', '0:t?'); // preserve embedded fonts/attachments
  ff.push('-c', 'copy');

  // Transcode MKV-incompatible subtitle codecs (mov_text, tx3g) to SRT
  // instead of triggering the conform flow with a copy error.
  const INCOMPAT_SUB = new Set(['mov_text', 'tx3g', 'c608', 'c708']);
  const outSubs = needsSubFilt ? embKeep : subStreams;
  outSubs.forEach((s, i) => {
    if (INCOMPAT_SUB.has(s.codec_name)) {
      ff.push('-c:s:' + i, 'srt');
      args.jobLog('Transcoding subtitle ' + i + ' (' + s.codec_name + ') to SRT for MKV compatibility.');
    }
  });

  const baseSubCount = needsSubFilt ? embKeep.length : subStreams.length;

  // Turkish subtitle filename detection — catches .tur, .tr, turkish, turkce, türkçe
  const parseLang = (filename) => {
    const n = path.basename(filename).toLocaleLowerCase('tr-TR').replace(/\.utf8tmp$/, '');
    // Turkish: .tur. / _tur_ / [tr] / [tur] / [turkish] / turkish / turkce / türkçe
    if (/[._\-]tur([._\-]|$)/.test(n) || /(?:^|[._\-\[])tr[._\-\]]/.test(n) ||
        /\[tur\]/.test(n) || /\[turkish\]/.test(n) ||
        n.includes('turkish') || n.includes('turkce') || n.includes('türkçe')) return 'tur';
    // English: .eng. / _en_ / [en] / [eng] / [english] / english
    if (/[._\-]eng([._\-]|$)/.test(n) || /(?:^|[._\-\[])en[._\-\]]/.test(n) ||
        /\[eng\]/.test(n) || /\[english\]/.test(n) ||
        n.includes('english')) return 'eng';
    return 'und';
  };

  convertedSubs.forEach((sf, i) => {
    ff.push('-metadata:s:s:' + (baseSubCount + i), 'language=' + parseLang(sf));
  });

  const audioOutCount = needsAudioFilt ? audioMapsToKeep.length : audioStreams.length;
  for (let i = 0; i < audioOutCount; i++) {
    ff.push('-disposition:a:' + i, i === 0 ? 'default' : '0');
  }

  const allOutEmbSubs = needsSubFilt ? embKeep : subStreams;
  const totalSubOut   = allOutEmbSubs.length + convertedSubs.length;
  let trDefaultSet    = false;

  for (let i = 0; i < totalSubOut; i++) {
    let subLang = 'und';
    if (i < allOutEmbSubs.length) {
      subLang = getLang(allOutEmbSubs[i]);
    } else {
      subLang = parseLang(convertedSubs[i - allOutEmbSubs.length]);
    }
    // Only first Turkish subtitle gets default
    if (TR_LANGS.has(subLang) && !trDefaultSet) {
      ff.push('-disposition:s:' + i, 'default');
      trDefaultSet = true;
    } else {
      ff.push('-disposition:s:' + i, '0');
    }
  }
  ff.push('-map_chapters', '0');
  ff.push(outputFile);

  args.jobLog('Running ffmpeg stream filter...');
  const startTime = Date.now();
  let res;
  try {
    res = await new Promise((resolve, reject) => {
      const proc = spawn(args.ffmpegPath, ff);
      let stderr = '';

      // Heartbeat every 30s — keeps Worker Stall Detector from firing on large files
      const heartbeat = setInterval(() => {
        const elapsed = Math.round((Date.now() - startTime) / 1000);
        args.jobLog('ffmpeg stream filter running... (' + elapsed + 's elapsed)');
      }, 30000);

      // Hard cap: 2 hours — cleared on close to avoid memory leak
      const killTimeout = setTimeout(() => { proc.kill('SIGKILL'); }, 7200000);

      proc.stderr.on('data', d => { stderr += d.toString(); });

      proc.on('close', (code, signal) => {
        clearInterval(heartbeat);
        clearTimeout(killTimeout);
        resolve({ status: signal ? null : code, stderr, signal });
      });

      proc.on('error', err => {
        clearInterval(heartbeat);
        clearTimeout(killTimeout);
        reject(err);
      });
    });
  } finally {
    for (const sf of convertedSubs) { if (sf.endsWith('.utf8tmp')) { try { fs.unlinkSync(sf); } catch(e) {} } }
  }

  if (res.status === null) {
    const msg = 'ffmpeg stream filter killed (timeout/signal)';
    args.jobLog(msg);
    try { fs.unlinkSync(outputFile); } catch(e) {}
    throw new Error(msg);
  }
  if (res.status !== 0) {
    const msg = 'ffmpeg stream filter failed (code ' + res.status + '): ' + (res.stderr || '').slice(0, 600);
    args.jobLog(msg);
    try { fs.unlinkSync(outputFile); } catch(e) {}
    throw new Error(msg);
  }

  // Defer external subtitle deletion to verifyOutput17 — prevents data loss if
  // downstream transcoding or verification fails after this step.
  // Store original path so verifyOutput17 can detect if transcode was reverted.
  args.variables.filterStreamsOrigFile = inputFile;
  args.variables.pendingDeleteSubs = extSubFiles;
  // Store expected audio count for verifyOutput17 integrity check
  args.variables.expectedAudioCount = finalAudio.length;
  args.jobLog('Stream filter done → ' + outputFile + '. Subtitles queued for deletion after verification.');
  return { outputFileObj: { _id: outputFile }, outputNumber: 1, variables: args.variables };
};

module.exports = async (args) => {
  const { spawnSync } = require('child_process');
  const inputFile = args.inputFileObj._id;
  args.jobLog('Rule 16: Pre-flight health check → ' + inputFile);

  const streams  = ((args.inputFileObj.ffProbeData || {}).streams || []);
  const format   = (args.inputFileObj.ffProbeData || {}).format || {};
  const duration = parseFloat(format.duration || '0');

  // 1. Dolby Vision detection — DV + NVENC = destroyed colors; skip cleanly
  const hasDV = streams.some(s =>
    s.codec_type === 'video' && (
      (s.profile || '').toLowerCase().includes('dolby vision') ||
      (JSON.stringify(s.side_data_list || [])).includes('DOVI') ||
      (JSON.stringify(s.side_data_list || [])).includes('dovi')
    )
  );
  if (hasDV) {
    args.jobLog('Dolby Vision detected — skipping transcode to preserve HDR color profile.');
    return { outputFileObj: args.inputFileObj, outputNumber: 2, variables: args.variables };
  }

  // HDR10+ (SMPTE 2094-40) — NVENC drops dynamic metadata; skip like DV
  const hasHDR10Plus = streams.some(s =>
    s.codec_type === 'video' && (
      JSON.stringify(s.side_data_list || []).includes('2094-40') ||
      JSON.stringify(s.side_data_list || []).includes('SMPTE2094')
    )
  );
  if (hasHDR10Plus) {
    args.jobLog('HDR10+ (SMPTE 2094-40) detected — skipping transcode to preserve dynamic metadata.');
    return { outputFileObj: args.inputFileObj, outputNumber: 2, variables: args.variables };
  }

  if (!streams.some(s => s.codec_type === 'video')) {
    args.jobLog('No video stream — skipping (mark processed).');
    return { outputFileObj: args.inputFileObj, outputNumber: 2, variables: args.variables };
  }

  const CRITICAL = /moov atom not found|Invalid data found when processing input|could not find codec parameters|no streams found/i;

  // 2. Decode first 10s
  const head = spawnSync(
    args.ffmpegPath,
    ['-v', 'error', '-i', inputFile, '-t', '10', '-f', 'null', '-'],
    { encoding: 'utf8', timeout: 120000, killSignal: 'SIGKILL' }
  );
  if (head.status === null || (head.status !== 0 && CRITICAL.test(head.stderr || ''))) {
    args.jobLog('Health check FAILED at start (exit ' + head.status + '): ' + (head.stderr || '').slice(0, 400));
    return { outputFileObj: args.inputFileObj, outputNumber: 3, variables: args.variables };
  }

  // 3. Decode last 30s — catches truncated / end-corrupted files
  if (duration > 60) {
    const seekTo = Math.max(0, duration - 30).toFixed(3);
    const tail = spawnSync(
      args.ffmpegPath,
      ['-v', 'error', '-ss', seekTo, '-i', inputFile, '-t', '30', '-f', 'null', '-'],
      { encoding: 'utf8', timeout: 120000, killSignal: 'SIGKILL' }
    );
    if (tail.status === null || (tail.status !== 0 && CRITICAL.test(tail.stderr || ''))) {
      args.jobLog('Health check FAILED at end (exit ' + tail.status + '): ' + (tail.stderr || '').slice(0, 400));
      return { outputFileObj: args.inputFileObj, outputNumber: 3, variables: args.variables };
    }
    args.jobLog('Health check passed (head + tail).');
  } else {
    args.jobLog('Health check passed.');
  }

  return { outputFileObj: args.inputFileObj, outputNumber: 1, variables: args.variables };
};

module.exports = async (args) => {
  const { spawnSync } = require('child_process');
  const fs   = require('fs');
  const path = require('path');
  const workingFile = args.inputFileObj._id;
  args.jobLog('Rule 17/19: Verifying output → ' + workingFile);

  const fail = (msg) => {
    args.jobLog('Verification FAILED: ' + msg);
    // Clean up pendingDeleteSubs on failure — originals stay intact
    if (args.variables && Array.isArray(args.variables.pendingDeleteSubs)) {
      args.variables.pendingDeleteSubs = [];
    }
    return { outputFileObj: args.inputFileObj, outputNumber: 2, variables: args.variables };
  };

  // 1. File must exist and be larger than 10 KB
  try {
    const stat = fs.statSync(workingFile);
    if (stat.size < 10240) return fail('file too small (' + stat.size + ' bytes)');
    args.jobLog('File size: ' + (stat.size / 1024 / 1024).toFixed(1) + ' MB');
  } catch (e) {
    return fail('cannot stat file: ' + e.message);
  }

  // 2. ffprobe: must have a video stream and a sane duration
  const ffprobePath = path.join(path.dirname(args.ffmpegPath), 'ffprobe');
  const probeResult = spawnSync(ffprobePath, [
    '-v', 'error', '-show_streams', '-show_format',
    '-print_format', 'json', workingFile,
  ], { encoding: 'utf8', timeout: 60000, killSignal: 'SIGKILL' });

  if (probeResult.status === 0 && probeResult.stdout) {
    try {
      const info        = JSON.parse(probeResult.stdout);
      const outStreams   = info.streams || [];
      const hasVideo    = outStreams.some(s => s.codec_type === 'video');
      const outDuration = parseFloat((info.format || {}).duration || '0');

      if (!hasVideo) return fail('no video stream in output');
      if (outDuration < 10) return fail('duration too short (' + outDuration.toFixed(1) + 's)');

      // Audio stream count sanity check
      const outAudioCount = outStreams.filter(s => s.codec_type === 'audio').length;
      const expAudio = (args.variables && typeof args.variables.expectedAudioCount === 'number')
        ? args.variables.expectedAudioCount : -1;
      if (expAudio > 0 && outAudioCount < expAudio) {
        return fail('audio streams dropped: expected ' + expAudio + ', got ' + outAudioCount);
      }
      if (expAudio > 0) args.jobLog('Audio streams OK: ' + outAudioCount + ' (expected ' + expAudio + ')');

      const origDuration = parseFloat(((args.inputFileObj.ffProbeData || {}).format || {}).duration || '0');
      if (origDuration > 0) {
        const ratio = outDuration / origDuration;
        if (ratio < 0.95) {
          return fail('duration mismatch — output ' + outDuration.toFixed(1) + 's vs original ' + origDuration.toFixed(1) + 's');
        }
        args.jobLog('Duration OK: ' + outDuration.toFixed(1) + 's (orig ' + origDuration.toFixed(1) + 's)');
      }
    } catch (e) {
      args.jobLog('ffprobe parse error (non-fatal): ' + e.message);
    }
  }

  // 3. Decode first 3 s for integrity check
  const probe = spawnSync(
    args.ffmpegPath,
    ['-v', 'error', '-i', workingFile, '-t', '3', '-f', 'null', '-'],
    { encoding: 'utf8', timeout: 60000, killSignal: 'SIGKILL' }
  );

  if (probe.status === null) {
    args.jobLog('Verification probe timed out — treating as passed.');
  } else {
    const CRITICAL = /Invalid data found when processing input|moov atom not found|could not find codec parameters/i;
    if (probe.status !== 0) return fail('exit ' + probe.status + ': ' + (probe.stderr || '').slice(0, 400));
    if (probe.stderr && CRITICAL.test(probe.stderr)) return fail('integrity error: ' + probe.stderr.slice(0, 400));
  }

  // Only delete external subs if the transcoded output was kept (not reverted).
  // If working file == original file that filterStreams ran on, transcode was
  // reverted (output was larger) — keep external subs to avoid data loss.
  const pending = (args.variables && Array.isArray(args.variables.pendingDeleteSubs))
    ? args.variables.pendingDeleteSubs : [];
  const origInputForFilter = (args.variables && args.variables.filterStreamsOrigFile) || '';
  const cacheRoot  = args.workDir || '';
  const isReverted = origInputForFilter && (workingFile === origInputForFilter);
  const isInCache  = cacheRoot && workingFile.startsWith(cacheRoot);
  const safeToDeleteSubs = !isReverted && (isInCache || !origInputForFilter);

  if (!safeToDeleteSubs && pending.length > 0) {
    args.jobLog('Transcode was reverted to original — keeping external subtitle files.');
  } else {
    for (const sf of pending) {
      try {
        fs.unlinkSync(sf);
        args.jobLog('Deleted embedded sub: ' + path.basename(sf));
      } catch (e) {
        args.jobLog('Could not delete sub ' + path.basename(sf) + ': ' + e.message);
      }
    }
  }
  args.variables.pendingDeleteSubs = [];
  args.variables.filterStreamsOrigFile = '';

  args.jobLog('Verification passed.');
  return { outputFileObj: args.inputFileObj, outputNumber: 1, variables: args.variables };
};

module.exports = async (args) => {
  const http = require('http');
  const db = args.inputFileObj.DB;
  const filePath = args.inputFileObj._id;

  args.jobLog('--- *arr & Jellyfin Sync Node ---');
  args.jobLog('Processing file: ' + filePath);

  // ── HTTP helper with retry + exponential backoff ─────────────────────────
  const makeRequest = (options, bodyData = null, retries = 2, baseDelay = 500) => {
    return new Promise((resolve, reject) => {
      const attempt = (n, delay) => {
        const req = http.request(options, (res) => {
          let data = '';
          res.on('data', (chunk) => data += chunk);
          res.on('end', () => resolve({ statusCode: res.statusCode, body: data }));
        });
        req.on('error', (e) => {
          if (n > 0) {
            args.jobLog('Request error (' + options.hostname + '): ' + e.message + ' — retrying in ' + delay + 'ms');
            setTimeout(() => attempt(n - 1, delay * 2), delay);
          } else {
            reject(e);
          }
        });
        req.on('timeout', () => {
          req.destroy();
          if (n > 0) {
            args.jobLog('Request timeout (' + options.hostname + ') — retrying in ' + delay + 'ms');
            setTimeout(() => attempt(n - 1, delay * 2), delay);
          } else {
            reject(new Error('timeout after retries'));
          }
        });
        if (bodyData) req.write(bodyData);
        req.end();
      };
      attempt(retries, baseDelay);
    });
  };

  // 1. Path & Library Detection
  let isTV = db === 'uhyljggCb' || db === 'vs2KAqJBd' || filePath.toLowerCase().includes('/tvshows/') || filePath.toLowerCase().includes('/anime/');
  let isMovie = db === 'L3WfEnP1U' || filePath.toLowerCase().includes('/movies/');

  let host = null, port = null, arrKey = null;
  if (isTV) {
    args.jobLog('Library detected: TV/Anime → target Sonarr');
    host = 'sonarr'; port = 8989;
    arrKey = 'YOUR_SONARR_OR_RADARR_API_KEY';
  } else if (isMovie) {
    args.jobLog('Library detected: Movies → target Radarr');
    host = 'radarr'; port = 7878;
    arrKey = 'YOUR_SONARR_OR_RADARR_API_KEY';
  } else {
    args.jobLog('Library: Other (' + db + ') → skipping *arr notification');
  }

  // 2. Notify Sonarr/Radarr
  if (host) {
    try {
      let matchedId = null;
      let cmdBody = {};

      if (isTV) {
        args.jobLog('Fetching series list from Sonarr...');
        const res = await makeRequest({ hostname: host, port, path: '/api/v3/series?apikey=' + arrKey, method: 'GET', timeout: 10000 });
        if (res.statusCode === 200) {
          const matched = JSON.parse(res.body).find(s => filePath.toLowerCase().startsWith(s.path.replace(/\/$/, '').toLowerCase() + '/'));
          if (matched) {
            matchedId = matched.id;
            cmdBody = { name: 'RescanSeries', seriesId: matchedId };
            args.jobLog('Matched series: "' + matched.title + '" (ID: ' + matchedId + ')');
          }
        }
      } else if (isMovie) {
        args.jobLog('Fetching movie list from Radarr...');
        const res = await makeRequest({ hostname: host, port, path: '/api/v3/movie?apikey=' + arrKey, method: 'GET', timeout: 10000 });
        if (res.statusCode === 200) {
          const matched = JSON.parse(res.body).find(m => filePath.toLowerCase().startsWith(m.path.replace(/\/$/, '').toLowerCase() + '/'));
          if (matched) {
            matchedId = matched.id;
            cmdBody = { name: 'RescanMovie', movieId: matchedId };
            args.jobLog('Matched movie: "' + matched.title + '" (ID: ' + matchedId + ')');
          }
        }
      }

      if (!matchedId) {
        args.jobLog('No path match — falling back to global rescan.');
        cmdBody = { name: isTV ? 'RescanSeries' : 'RescanMovie' };
      }

      const payload = JSON.stringify(cmdBody);
      const cmdRes = await makeRequest({
        hostname: host, port,
        path: '/api/v3/command?apikey=' + arrKey,
        method: 'POST',
        headers: { 'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(payload) },
        timeout: 10000
      }, payload);
      args.jobLog('*arr response: HTTP ' + cmdRes.statusCode);
    } catch (e) {
      args.jobLog('*arr notify failed (non-fatal): ' + e.message);
    }
  }

  // 3. Notify Jellyfin
  const jfKey = 'YOUR_JELLYFIN_API_KEY';
  const jfPayload = JSON.stringify({ Updates: [{ Path: filePath, UpdateType: 'Modified' }] });
  for (const jfHost of ['jellyfin', 'YOUR_JELLYFIN_IP']) {
    try {
      args.jobLog('Notifying Jellyfin on ' + jfHost + '...');
      const res = await makeRequest({
        hostname: jfHost, port: 8096,
        path: '/Library/Media/Updated?api_key=' + jfKey,
        method: 'POST',
        headers: { 'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(jfPayload) },
        timeout: 5000
      }, jfPayload, 1);  // 1 retry for Jellyfin
      args.jobLog('Jellyfin (' + jfHost + '): HTTP ' + res.statusCode);
      if (res.statusCode === 200 || res.statusCode === 204) { break; }
    } catch (e) {
      args.jobLog('Jellyfin (' + jfHost + ') failed: ' + e.message);
    }
  }

  // 4. Notify Bazarr — wait 15s for Sonarr/Radarr rescan to complete first
  await new Promise(resolve => setTimeout(resolve, 15000));
  args.jobLog('Bazarr delay elapsed, sending subtitle search request...');
  const bzKey = 'YOUR_BAZARR_API_KEY';
  try {
    const encoded = encodeURIComponent(filePath);
    if (isTV) {
      const epRes = await makeRequest({ hostname: 'bazarr', port: 6767, path: '/api/episodes?path=' + encoded + '&apikey=' + bzKey, method: 'GET', timeout: 10000 });
      if (epRes.statusCode === 200) {
        const eps = (JSON.parse(epRes.body).data || []);
        if (eps.length > 0) {
          const sp = JSON.stringify({ episodeid: [eps[0].sonarrEpisodeId] });
          const sr = await makeRequest({ hostname: 'bazarr', port: 6767, path: '/api/episodes/wanted/search?apikey=' + bzKey, method: 'POST', headers: { 'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(sp) }, timeout: 10000 }, sp);
          args.jobLog('Bazarr episode search: HTTP ' + sr.statusCode);
        } else { args.jobLog('Bazarr: episode not found.'); }
      }
    } else if (isMovie) {
      const mvRes = await makeRequest({ hostname: 'bazarr', port: 6767, path: '/api/movies?path=' + encoded + '&apikey=' + bzKey, method: 'GET', timeout: 10000 });
      if (mvRes.statusCode === 200) {
        const mvs = (JSON.parse(mvRes.body).data || []);
        if (mvs.length > 0) {
          const sp = JSON.stringify({ radarrid: [mvs[0].radarrId] });
          const sr = await makeRequest({ hostname: 'bazarr', port: 6767, path: '/api/movies/wanted/search?apikey=' + bzKey, method: 'POST', headers: { 'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(sp) }, timeout: 10000 }, sp);
          args.jobLog('Bazarr movie search: HTTP ' + sr.statusCode);
        } else { args.jobLog('Bazarr: movie not found.'); }
      }
    }
  } catch (e) {
    args.jobLog('Bazarr notify failed (non-fatal): ' + e.message);
  }

  return { outputFileObj: args.inputFileObj, outputNumber: 1, variables: args.variables };
};

