module.exports = async (args) => {
  const { spawnSync } = require('child_process');
  const fs   = require('fs');
  const path = require('path');

  const THRESHOLD  = 80;    // VMAF score minimum (0-100). Below this = revert to original.
  const SAMPLE_SEC = '30';  // Compare first N seconds only (speed vs accuracy).
  const VMAF_THREADS = '4';

  const encodedFile = args.inputFileObj._id;
  const refFile     = (args.variables && (args.variables.filterStreamsOrigFile || args.variables.flowOrigFile)) || '';

  const pass = (msg) => {
    args.jobLog('VMAF: ' + msg + ' — treating as PASS.');
    return { outputFileObj: args.inputFileObj, outputNumber: 1, variables: args.variables };
  };
  const fail = (msg) => {
    args.jobLog('VMAF FAIL: ' + msg + ' — reverting to original.');
    return { outputFileObj: args.inputFileObj, outputNumber: 2, variables: args.variables };
  };

  if (!refFile) return pass('no reference file stored (filterStreamsOrigFile not set)');

  try { fs.statSync(refFile); } catch(e) {
    return pass('reference file not accessible: ' + path.basename(refFile));
  }
  try { fs.statSync(encodedFile); } catch(e) {
    return pass('encoded file not accessible: ' + path.basename(encodedFile));
  }

  const vmafLog = '/tmp/tdarr_vmaf_' + Date.now() + '.json';
  args.jobLog('VMAF: scoring first ' + SAMPLE_SEC + 's…');
  args.jobLog('  ref:      ' + path.basename(refFile));
  args.jobLog('  distorted: ' + path.basename(encodedFile));

  // ffmpeg: [0]=distorted [1]=reference → libvmaf
  const result = spawnSync(args.ffmpegPath, [
    '-t', SAMPLE_SEC, '-i', encodedFile,
    '-t', SAMPLE_SEC, '-i', refFile,
    '-lavfi', '[1:v][0:v]libvmaf=n_threads=' + VMAF_THREADS +
              ':log_fmt=json:log_path=' + vmafLog,
    '-f', 'null', '-'
  ], { encoding: 'utf8', timeout: 300000, killSignal: 'SIGKILL' });

  // libvmaf not compiled in → skip gracefully
  if (result.stderr && /No such filter/.test(result.stderr)) {
    return pass('libvmaf filter not available in this ffmpeg build');
  }

  if (result.status === null) return pass('VMAF probe timed out');

  if (result.status !== 0) {
    args.jobLog('VMAF: ffmpeg exited ' + result.status + ': ' + (result.stderr || '').slice(0, 300));
    return pass('ffmpeg error during VMAF — skipping gate');
  }

  try {
    const report = JSON.parse(fs.readFileSync(vmafLog, 'utf8'));
    const score  = report['pooled_metrics']['vmaf']['mean'];
    args.jobLog('VMAF score: ' + score.toFixed(2) + ' (threshold: ' + THRESHOLD + ')');
    try { fs.unlinkSync(vmafLog); } catch(e) {}

    if (score < THRESHOLD) {
      return fail('score ' + score.toFixed(2) + ' < ' + THRESHOLD);
    }
    args.jobLog('VMAF PASS: ' + score.toFixed(2));
    return { outputFileObj: args.inputFileObj, outputNumber: 1, variables: args.variables };

  } catch(e) {
    try { fs.unlinkSync(vmafLog); } catch(e2) {}
    return pass('could not parse VMAF result (' + e.message + ')');
  }
};

