    args.jobLog(
      'Disk space OK: ' + (available/1073741824).toFixed(1) + ' GB free, ' +
      'need ' + (needed/1073741824).toFixed(1) + ' GB.'
    );
  } catch (e) {
    args.jobLog('Disk space check error (proceeding): ' + e.message);
  }

  return { outputFileObj: args.inputFileObj, outputNumber: 1, variables: args.variables };
};

