module.exports = async (args) => {
  const streams = ((args.inputFileObj.ffProbeData || {}).streams || []);
  const IMAGE_CODECS = new Set(['mjpeg', 'png', 'bmp', 'gif', 'tiff', 'webp']);
  const vs = streams.find(s => s.codec_type === 'video' && !IMAGE_CODECS.has(s.codec_name));

  if (!vs) return { outputFileObj: args.inputFileObj, outputNumber: 1, variables: args.variables };

  const ct  = (vs.color_transfer  || '').toLowerCase();
  const cp  = (vs.color_primaries || '').toLowerCase();
  const cs  = (vs.color_space     || '').toLowerCase();
  const cr  = (vs.color_range     || '').toLowerCase();

  // Detect HDR10 / HLG
  const isHDR10 = ct === 'smpte2084'  || cp === 'bt2020';
  const isHLG   = ct === 'arib-std-b67';
  const isHDR   = isHDR10 || isHLG;

  const cmd = (args.variables || {}).ffmpegCommand;
  if (!cmd || !Array.isArray(cmd.streams)) {
    args.jobLog('HDR check: ffmpegCommand not ready — skipping.');
    return { outputFileObj: args.inputFileObj, outputNumber: 1, variables: args.variables };
  }

  if (!isHDR) {
    args.jobLog('SDR content — no HDR metadata injection needed.');
    return { outputFileObj: args.inputFileObj, outputNumber: 1, variables: args.variables };
  }

  args.jobLog('HDR detected: transfer=' + ct + ' primaries=' + cp + ' — injecting color metadata into encode.');

  // Inject color metadata into the video stream's outputArgs
  for (const stream of cmd.streams) {
    if (stream.codec_type !== 'video' || IMAGE_CODECS.has(stream.codec_name)) continue;
    // Remove pre-existing -color_* flags to prevent duplicates from encoder nodes
    stream.outputArgs = (stream.outputArgs || []).filter(a => !String(a).startsWith('-color'));

    // Add color metadata flags to preserve HDR on re-encode
    const colorArgs = [
      '-color_primaries', cp || 'bt2020',
      '-color_trc',       ct || (isHLG ? 'arib-std-b67' : 'smpte2084'),
      '-colorspace',      cs || 'bt2020nc',
    ];
    if (cr === 'tv' || cr === 'limited') colorArgs.push('-color_range', 'tv');

    // Append to existing outputArgs (after encoder options)
    stream.outputArgs = (stream.outputArgs || []).concat(colorArgs);
    args.jobLog('Color args injected: ' + colorArgs.join(' '));
  }

  return { outputFileObj: args.inputFileObj, outputNumber: 1, variables: args.variables };
};

